package com.parkflow.mall.gateway;
import com.parkflow.mall.gateway.controller.VisionGatewayController;import com.parkflow.mall.gateway.vision.VisionServiceProxy;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;import org.springframework.boot.test.mock.mockito.MockBean;import org.springframework.http.ResponseEntity;import org.springframework.mock.web.MockMultipartFile;import org.springframework.test.web.servlet.MockMvc;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@WebMvcTest(VisionGatewayController.class)class VisionGatewayControllerTests{@Autowired MockMvc mvc;@MockBean VisionServiceProxy proxy;@Test void forwardsAuthorizationAndMultipartFile()throws Exception{when(proxy.ocr(any(),any(),any(),any())).thenReturn(ResponseEntity.ok("{}"));MockMultipartFile image=new MockMultipartFile("image","59A1-12345.jpg","image/jpeg","demo".getBytes());mvc.perform(multipart("/api/vision/ocr/plate").file(image).header("Authorization","Bearer staff").param("cameraId","cam-1")).andExpect(status().isOk());verify(proxy).ocr(eq("Bearer staff"),any(),eq("cam-1"),isNull());mvc.perform(post("/internal/vision/ocr/plate")).andExpect(status().isNotFound());}}
